// command_manifest.hpp - Generated at compile-time, not hand-written
#pragma once
#include <string_view>
#include <functional>
#include <map>

// Each command knows its own wiring requirements
struct CommandManifest {
    std::string_view id;                    // "file.new"
    std::string_view category;              // "File"
    std::string_view label;                 // "New File..."
    std::string_view accelerator;           // "Ctrl+N"
    std::string_view breadcrumb_path;       // "File > New > File"
    
    // Wiring specification - what this command NEEDS from the framework
    struct Requirements {
        bool needs_file_system;             // true
        bool needs_editor_window;           // true
        bool needs_dialog_manager;          // true
        std::string_view dialog_type;       // "save_dialog"
        std::string_view default_extension; // ".txt"
    } requirements;
    
    // Reverse link - what provides this capability
    std::string_view provider_module;       // "file_manager.dll"
    std::string_view provider_symbol;       // "ShowNewFileDialog"
    
    // Self-validation: generates compile error if provider missing
    static_assert(!provider_module.empty(), "Command declared but no provider implemented");
};

// The manifest is the source of truth - menus generate from this
#define DECLARE_COMMAND(id, cat, label, accel, ...) \
    inline constexpr CommandManifest cmd_##id = {#id, cat, label, accel, __VA_ARGS__};
