// menu_generator.cpp - Creates actual Win32 menus from manifest
#include "command_manifest.hpp"
#include <windows.h>

class MenuManifestor {
public:
    // Generates HMENU from compile-time command manifests
    template<typename... Commands>
    static HMENU GenerateMenuBar() {
        HMENU hMenu = CreateMenu();
        
        // Group by category automatically
        auto categories = GroupByCategory<Commands...>();
        
        // Create actual Win32 menu structures
        for (const auto& [category, commands] : categories) {
            HMENU hSubMenu = CreatePopupMenu();
            
            for (const auto& cmd : commands) {
                // Real Win32 menu items with IDs
                UINT itemID = CommandRegistry::Register(cmd);
                
                AppendMenuA(hSubMenu, MF_STRING, itemID, cmd.label.data());
                
                // Set accelerator if specified
                if (!cmd.accelerator.empty()) {
                    RegisterAccelerator(cmd.accelerator, itemID);
                }
            }
            
            AppendMenuA(hMenu, MF_POPUP, (UINT_PTR)hSubMenu, category.data());
        }
        
        return hMenu;
    }
    
    // Right-click context menu from breadcrumb path
    static HMENU GenerateContextMenu(std::string_view breadcrumb) {
        HMENU hMenu = CreatePopupMenu();
        
        // Parse breadcrumb: "File > New > File"
        auto parts = SplitBreadcrumb(breadcrumb);
        
        // Add "Show in Explorer" - ACTUAL implementation
        AppendMenuA(hMenu, MF_STRING, ID_SHOW_IN_EXPLORER, "Show in Explorer");
        
        // Add "Copy Path" - ACTUAL implementation  
        AppendMenuA(hMenu, MF_STRING, ID_COPY_PATH, "Copy Full Path");
        
        // Add "Copy Relative Path" - ACTUAL implementation
        AppendMenuA(hMenu, MF_STRING, ID_COPY_REL_PATH, "Copy Relative Path");
        
        // Add separator
        AppendMenuA(hMenu, MF_SEPARATOR, 0, nullptr);
        
        // Add breadcrumb navigation (click to jump)
        for (size_t i = 0; i < parts.size(); ++i) {
            std::string label;
            for (size_t j = 0; j <= i; ++j) {
                if (j > 0) label += " > ";
                label += parts[j];
            }
            AppendMenuA(hMenu, MF_STRING, ID_BREADCRUMB_BASE + i, label.c_str());
        }
        
        return hMenu;
    }
};
