// breadcrumb_oracle.hpp - Knows where you are and where you can go
#pragma once
#include <vector>
#include <string>
#include <functional>

struct BreadcrumbNode {
    std::string label;                      // "src"
    std::string full_path;                  // "D:/project/src"
    std::string relative_path;              // "src"
    bool is_file;                           // false (directory)
    bool is_modified;                       // false
    
    // What can you do HERE specifically
    struct Actions {
        std::function<void()> on_click;     // Navigate to this folder
        std::function<void()> on_right_click; // Show context menu
        std::function<void()> on_middle_click; // Open in new tab
    } actions;
};

class BreadcrumbOracle {
public:
    // Called when editor changes file
    void UpdateLocation(const std::string& file_path) {
        current_path_ = file_path;
        nodes_ = ParsePath(file_path);
        
        // Manifest what UI elements should exist based on location
        ManifestUI();
    }
    
    // Generates actual breadcrumb UI elements
    void ManifestUI() {
        // Clear existing
        breadcrumb_hwnd_ = CreateWindowEx(
            0, "STATIC", nullptr,
            WS_CHILD | WS_VISIBLE | SS_OWNERDRAW,
            0, 0, 800, 24,
            parent_hwnd_, (HMENU)IDC_BREADCRUMB,
            hInstance_, nullptr
        );
        
        // Create clickable segments
        int x = 0;
        for (size_t i = 0; i < nodes_.size(); ++i) {
            auto& node = nodes_[i];
            
            HWND hSegment = CreateWindowEx(
                0, "BUTTON", node.label.c_str(),
                WS_CHILD | WS_VISIBLE | BS_OWNERDRAW | BS_FLAT,
                x, 0, MeasureText(node.label), 24,
                breadcrumb_hwnd_, (HMENU)(ID_BREADCRUMB_SEGMENT + i),
                hInstance_, nullptr
            );
            
            // Set up right-click handler for THIS specific segment
            SetWindowSubclass(hSegment, BreadcrumbSubclassProc, i, 
                reinterpret_cast<DWORD_PTR>(&node));
            
            x += MeasureText(node.label) + 20; // + arrow
        }
    }
    
    // Right-click handler - ACTUAL implementation
    static LRESULT CALLBACK BreadcrumbSubclassProc(HWND hWnd, UINT uMsg,
        WPARAM wParam, LPARAM lParam, UINT_PTR uIdSubclass, DWORD_PTR dwRefData) {
        
        if (uMsg == WM_CONTEXTMENU) {
            BreadcrumbNode* node = reinterpret_cast<BreadcrumbNode*>(dwRefData);
            
            HMENU hMenu = CreatePopupMenu();
            
            // ACTUAL working commands
            AppendMenuA(hMenu, MF_STRING, ID_OPEN_FOLDER, 
                ("Open " + node->label + " in Explorer").c_str());
            AppendMenuA(hMenu, MF_STRING, ID_COPY_PATH, "Copy Path");
            AppendMenuA(hMenu, MF_STRING, ID_COPY_REL_PATH, "Copy Relative Path");
            
            if (node->is_file) {
                AppendMenuA(hMenu, MF_SEPARATOR, 0, nullptr);
                AppendMenuA(hMenu, MF_STRING, ID_REVEAL_IN_TREE, "Reveal in File Tree");
            }
            
            // Track and execute
            POINT pt;
            GetCursorPos(&pt);
            int cmd = TrackPopupMenu(hMenu, TPM_RETURNCMD, pt.x, pt.y, 0, hWnd, nullptr);
            
            // ACTUAL implementations
            switch (cmd) {
                case ID_OPEN_FOLDER:
                    ShellExecuteA(nullptr, "open", node->full_path.c_str(), 
                        nullptr, nullptr, SW_SHOWNORMAL);
                    break;
                case ID_COPY_PATH:
                    CopyToClipboard(node->full_path);
                    break;
                case ID_COPY_REL_PATH:
                    CopyToClipboard(node->relative_path);
                    break;
            }
            
            DestroyMenu(hMenu);
            return 0;
        }
        
        return DefSubclassProc(hWnd, uMsg, wParam, lParam);
    }
    
private:
    std::string current_path_;
    std::vector<BreadcrumbNode> nodes_;
    HWND breadcrumb_hwnd_;
    HWND parent_hwnd_;
};
