// settings_manifest.hpp - Every setting knows its UI and persistence
#pragma once
#include <variant>
#include <string>

// Base setting type - knows how to render itself and where to save
template<typename T>
struct Setting {
    std::string key;                        // "editor.font_size"
    std::string category;                   // "Editor"
    std::string label;                      // "Font Size"
    std::string description;                // "Editor font size in points"
    T default_value;
    T min_value;                            // For numeric
    T max_value;                            // For numeric
    std::vector<std::pair<T, std::string>> options; // For enum/bool
    
    // UI manifestation
    enum class UIType { Checkbox, Slider, Dropdown, Text, Hotkey };
    UIType ui_type;
    
    // Persistence
    std::string registry_path;              // "Software\\RawrXD\\Editor"
    std::string config_file_key;            // "editor.font_size"
    
    // Real implementation - not placeholder
    T GetValue() const {
        // Try registry first
        T reg_val = ReadFromRegistry<T>(registry_path, key);
        if (reg_val) return *reg_val;
        
        // Fall back to config file
        T file_val = ReadFromConfig<T>(config_file_key);
        if (file_val) return *file_val;
        
        return default_value;
    }
    
    void SetValue(const T& value) {
        WriteToRegistry(registry_path, key, value);
        WriteToConfig(config_file_key, value);
        
        // Notify subscribers immediately
        OnChanged(value);
    }
    
    // Generate actual Win32 control for this setting
    HWND CreateControl(HWND parent, int x, int y, int width) const {
        switch (ui_type) {
            case UIType::Checkbox: {
                HWND hCheck = CreateWindowEx(
                    0, "BUTTON", label.c_str(),
                    WS_CHILD | WS_VISIBLE | BS_AUTOCHECKBOX,
                    x, y, width, 20,
                    parent, (HMENU)ControlID(), hInstance_, nullptr
                );
                Button_SetCheck(hCheck, GetValue() ? BST_CHECKED : BST_UNCHECKED);
                return hCheck;
            }
            
            case UIType::Slider: {
                // Label
                CreateWindowEx(0, "STATIC", label.c_str(),
                    WS_CHILD | WS_VISIBLE,
                    x, y, width, 16, parent, nullptr, hInstance_, nullptr);
                
                // Trackbar
                HWND hSlider = CreateWindowEx(
                    0, TRACKBAR_CLASS, nullptr,
                    WS_CHILD | WS_VISIBLE | TBS_AUTOTICKS,
                    x, y + 18, width, 30,
                    parent, (HMENU)ControlID(), hInstance_, nullptr
                );
                
                SendMessage(hSlider, TBM_SETRANGE, TRUE, 
                    MAKELPARAM(min_value, max_value));
                SendMessage(hSlider, TBM_SETPOS, TRUE, GetValue());
                
                return hSlider;
            }
            
            case UIType::Dropdown: {
                // Label
                CreateWindowEx(0, "STATIC", label.c_str(),
                    WS_CHILD | WS_VISIBLE,
                    x, y, width, 16, parent, nullptr, hInstance_, nullptr);
                
                // Combobox
                HWND hCombo = CreateWindowEx(
                    0, "COMBOBOX", nullptr,
                    WS_CHILD | WS_VISIBLE | CBS_DROPDOWNLIST | CBS_HASSTRINGS,
                    x, y + 18, width, 200,
                    parent, (HMENU)ControlID(), hInstance_, nullptr
                );
                
                for (const auto& [val, name] : options) {
                    ComboBox_AddString(hCombo, name.c_str());
                    if (val == GetValue()) {
                        ComboBox_SetCurSel(hCombo, ComboBox_GetCount(hCombo) - 1);
                    }
                }
                
                return hCombo;
            }
        }
        return nullptr;
    }
    
    std::function<void(const T&)> OnChanged;
};

// Concrete settings - actual production toggles
namespace Settings {
    inline constexpr Setting<bool> kEnableAI = {
        "ai.enabled", "AI Features", "Enable AI Assistance",
        "Turn on inline suggestions and chat", true,
        false, true, {},
        Setting<bool>::UIType::Checkbox,
        "Software\\RawrXD\\AI", "ai.enabled"
    };
    
    inline constexpr Setting<int> kFontSize = {
        "editor.font_size", "Editor", "Font Size",
        "Editor font size in points", 12, 8, 32, {},
        Setting<int>::UIType::Slider,
        "Software\\RawrXD\\Editor", "editor.font_size"
    };
    
    inline constexpr Setting<std::string> kTheme = {
        "ui.theme", "Appearance", "Color Theme",
        "IDE color scheme", "dark",
        "", "", {
            {"dark", "Dark"},
            {"light", "Light"},
            {"system", "System Default"}
        },
        Setting<std::string>::UIType::Dropdown,
        "Software\\RawrXD\\UI", "ui.theme"
    };
}
