        // Group by category
        std::map<std::string, std::vector<CommandInfo>> by_category;
        for (const auto& cmd : commands) {
            by_category[cmd.category].push_back(cmd);
        }
        
        // Generate menu bar
        menu_file << "inline HMENU CreateGeneratedMenuBar() {\n";
        menu_file << "    HMENU hMenu = CreateMenu();\n\n";
        
        for (const auto& [category, cmds] : by_category) {
            menu_file << "    // " << category << " menu\n";
            menu_file << "    {\n";
            menu_file << "        HMENU h" << Sanitize(category) 
