                250, 24, width - 250 - 200, height - 48, SWP_NOZORDER);
            
            // Status bar (bottom)
            DeferWindowPos(hdwp, GetDlgItem(hWnd, IDC_STATUS), nullptr,
                0, height - 24, width, 24, SWP_NOZORDER);
            
            EndDeferWindowPos(hdwp);
            return 0;
        }
        
        case WM_COMMAND: {
            int wmId = LOWORD(wParam);
            
            // Handle all menu commands through wiring manifest
            if (HandleWiredCommand(wmId)) {
                return 0;
            }
            
            // Unwired commands show diagnostic
            ShowUnwiredCommandDialog(wmId);
            return 0;
        }
        
        case WM_NOTIFY: {
            NMHDR* pnmh = (NMHDR*)lParam;
            
            // File tree notifications
            if (pnmh->idFrom == IDC_FILETREE) {
                return HandleFileTreeNotify(pnmh);
            }
            
            // Breadcrumb notifications
            if (pnmh->idFrom == IDC_BREADCRUMB) {
                return HandleBreadcrumbNotify(pnmh);
            }
            
            return 0;
        }
        
        case WM_DESTROY:
            PostQuitMessage(0);
            return 0;
    }
    
    return DefWindowProc(hWnd, uMsg, wParam, lParam);
