// Capability signatures - components identify by what they DO
using Capability = size_t;
constexpr Capability CAP_CONTAINER = 0x1;      // Can hold other things
constexpr Capability CAP_NAVIGATE = 0x2;       // Can change location
constexpr Capability CAP_DISPLAY = 0x4;        // Can show content
constexpr Capability CAP_MANIPULATE = 0x8;     // Can modify state
constexpr Capability CAP_ROUTE = 0x10;         // Can delegate actions
constexpr Capability CAP_PERSIST = 0x20;       // Can save/restore

// Anonymous capability provider
struct Node {
    void* handle;                              // HWND or internal
    Capability caps;                           // What it can do
    std::vector<std::shared_ptr<Node>> inputs; // What feeds into it
    std::vector<std::weak_ptr<Node>> outputs;  // What it feeds
    
    // Self-identifying behavior
    std::function<void(void*)> on_activate;    // Triggered when used
    std::function<void*(const char*)> on_resolve; // Returns sub-node by path
    
    bool Provides(Capability c) const { return (caps & c) == c; }
};

// Manifestation oracle - creates structure from capability requirements
class Oracle {
    std::vector<std::shared_ptr<Node>> registry_;
    
public:
    // Manifest whatever satisfies the capability gap
    std::shared_ptr<Node> Manifest(Capability required, void* parent_handle) {
        auto node = std::make_shared<Node>();
        node->caps = required;
        node->handle = parent_handle;
        
        // Auto-wire: if needs navigation, find or create navigator
        if (required & CAP_NAVIGATE) {
            auto nav = FindOrCreate(CAP_NAVIGATE | CAP_DISPLAY, node.get());
            node->inputs.push_back(nav);
        }
        
        // Auto-wire: if manipulates, needs persistence
        if (required & CAP_MANIPULATE) {
            auto store = FindOrCreate(CAP_PERSIST, node.get());
            node->outputs.push_back(store);
        }
        
        registry_.push_back(node);
        return node;
    }
    
    std::shared_ptr<Node> FindOrCreate(Capability caps, void* context) {
        for (auto& n : registry_) {
            if (n->Provides(caps) && n->handle == context) {
                return n;
            }
        }
        return Manifest(caps, context);
    }
    
    // Route action to appropriate node by capability, not name
    void Route(void* origin, Capability target_caps, void* data) {
        for (auto& n : registry_) {
            if (n->Provides(target_caps) && IsReachable(origin, n.get())) {
                if (n->on_activate) n->on_activate(data);
                return;
            }
        }
    }
    
private:
    bool IsReachable(void* from, Node* to) {
        // Topological reachability in manifestation graph
        return true; // Simplified
    }
};
