        // Scan for capability declarations in binary
        auto caps = ScanCapabilityDeclarations();
        
        // Group by capability signature, not "category"
        std::map<Capability, std::vector<Capability>> groups;
        for (auto& c : caps) {
            groups[c & 0xFF0].push_back(c); // Group by high nibble
        }
        
        // Manifest sub-containers
        for (auto& [group_caps, items] : groups) {
            HMENU hSub = CreatePopupMenu();
            
            for (auto& item_cap : items) {
                UINT id = 0x4000 + command_map_.size();
                
                // Get icon for capability
                const char* icon = CapabilityIcon(item_cap);
                
                AppendMenuA(hSub, MF_STRING, id, icon);
                
                // Map to node that provides this capability
