            // Append to main container with group icon
            AppendMenuA(hMenu, MF_POPUP, (UINT_PTR)hSub, 
                CapabilityIcon(group_caps));
        }
        
        SetMenu((HWND)parent, hMenu);
        
        // Command handler - routes by capability lookup
        router->on_activate = [this](void* data) {
            UINT cmd = (UINT)(size_t)data;
            auto it = command_map_.find(cmd);
            if (it != command_map_.end() && it->second->on_activate) {
                it->second->on_activate(nullptr);
            }
        };
    }
    
    const char* CapabilityIcon(Capability c) {
        if (c & CAP_CONTAINER) return "\xF0\x9F\x93\x81"; // Folder
        if (c & CAP_DISPLAY) return "\xF0\x9F\x93\x84";   // Document
        if (c & CAP_MANIPULATE) return "\xE2\x9C\x8F";    // Pencil
        if (c & CAP_PERSIST) return "\xF0\x9F\x92\xBE";   // Floppy
        if (c & CAP_NAVIGATE) return "\xF0\x9F\xA7\xAD";  // Compass
        return "\xE2\x97\x8F"; // Circle
