constexpr Capability CAP_NONE = 0x0;
constexpr Capability CAP_CONTAINER = 0x1;
constexpr Capability CAP_NAVIGATE = 0x2;
constexpr Capability CAP_DISPLAY = 0x4;
constexpr Capability CAP_MANIPULATE = 0x8;
constexpr Capability CAP_ROUTE = 0x10;
constexpr Capability CAP_PERSIST = 0x20;
constexpr Capability CAP_STREAM = 0x40;

struct Node {
    void* handle;
    Capability caps;
    std::vector<std::shared_ptr<Node>> inputs;
    std::vector<std::weak_ptr<Node>> outputs;
    std::function<void(void*)> on_activate;
    std::function<void*(const char*)> on_resolve;
    std::function<void(int, int)> on_resize;
    
    bool Provides(Capability c) const { return (caps & c) == c; }
    bool ProvidesAny(Capability c) const { return (caps & c) != 0; }
};

class Oracle {
    std::vector<std::shared_ptr<Node>> registry_;
    HWND root_hwnd_;
    
public:
    void SetRoot(HWND h) { root_hwnd_ = h; }
    
    std::shared_ptr<Node> Manifest(Capability required, void* parent) {
        auto node = std::make_shared<Node>();
        node->caps = required;
        node->handle = nullptr;
        
        if (required & CAP_NAVIGATE) {
            auto nav = FindExisting(CAP_NAVIGATE | CAP_DISPLAY, parent);
            if (!nav) nav = CreateNavigator(parent);
            if (nav) node->inputs.push_back(nav);
        }
        
        if (required & CAP_MANIPULATE) {
            auto store = FindExisting(CAP_PERSIST, parent);
            if (!store) store = CreatePersistence(parent);
            if (store) node->outputs.push_back(store);
        }
        
        if (required & CAP_DISPLAY) {
            auto stream = FindExisting(CAP_STREAM, parent);
            if (stream) node->inputs.push_back(stream);
        }
        
        registry_.push_back(node);
        return node;
    }
    
    std::shared_ptr<Node> FindExisting(Capability caps, void* context) {
        for (auto& n : registry_) {
            if (n->Provides(caps) && n->handle == context) return n;
        }
        return nullptr;
    }
    
    std::shared_ptr<Node> FindByHandle(void* h) {
        for (auto& n : registry_) {
            if (n->handle == h) return n;
        }
        return nullptr;
    }
    
    void Route(void* origin, Capability target_caps, void* data) {
        for (auto& n : registry_) {
            if (n->Provides(target_caps)) {
                RECT rc;
                GetWindowRect((HWND)origin, &rc);
                POINT pt = { rc.left, rc.top };
                ScreenToClient(root_hwnd_, &pt);
                
                if (PtInRect(&rc, pt) || n->inputs.empty()) {
                    if (n->on_activate) n->on_activate(data);
                    return;
                }
            }
        }
    }
    
    void ResizeAll(int w, int h) {
        for (auto& n : registry_) {
            if (n->on_resize) n->on_resize(w, h);
        }
    }
    
private:
    std::shared_ptr<Node> CreateNavigator(void* parent) {
        auto node = std::make_shared<Node>();
        node->caps = CAP_NAVIGATE | CAP_DISPLAY;
        node->handle = parent;
        registry_.push_back(node);
        return node;
    }
    
    std::shared_ptr<Node> CreatePersistence(void* parent) {
        auto node = std::make_shared<Node>();
        node->caps = CAP_PERSIST;
        node->handle = parent;
        registry_.push_back(node);
        return node;
    }
};

