#include "α.hpp"

#define IDC_CONTAINER 0x1000
#define IDM_REVEAL 0x2001
#define IDM_COPYPATH 0x2002
#define IDM_COPYREL 0x2003
#define IDM_EXECUTE 0x2004

static std::map<HTREEITEM, std::string> g_item_paths;
static HWND g_container_hwnd = nullptr;

static int CALLBACK TreeCompare(LPARAM lParam1, LPARAM lParam2, LPARAM lParamSort) {
    const char* s1 = ((std::string*)lParam1)->c_str();
    const char* s2 = ((std::string*)lParam2)->c_str();
    return strcmp(s1, s2);
}

static void PopulateTree(HWND hTree, HTREEITEM hParent, const std::string& path) {
    WIN32_FIND_DATAA fd;
    std::string search = path + "\\*";
    HANDLE hFind = FindFirstFileA(search.c_str(), &fd);
    
    if (hFind == INVALID_HANDLE_VALUE) return;
    
    do {
        if (strcmp(fd.cFileName, ".") == 0 || strcmp(fd.cFileName, "..") == 0) continue;
        
        std::string* stored = new std::string(path);
        stored->append("\\").append(fd.cFileName);
        
        SHFILEINFOA sfi = {};
        DWORD attr = (fd.dwFileAttributes & FILE_ATTRIBUTE_DIRECTORY) ? FILE_ATTRIBUTE_DIRECTORY : 0;
        SHGetFileInfoA(stored->c_str(), attr, &sfi, sizeof(sfi), 
            SHGFI_SYSICONINDEX | SHGFI_SMALLICON | SHGFI_USEFILEATTRIBUTES);
        
        TVINSERTSTRUCTA tvis = {};
        tvis.hParent = hParent;
        tvis.hInsertAfter = TVI_SORT;
        tvis.item.mask = TVIF_TEXT | TVIF_IMAGE | TVIF_SELECTEDIMAGE | TVIF_PARAM | TVIF_CHILDREN;
        
        char display[MAX_PATH];
        StringCchCopyA(display, MAX_PATH, fd.cFileName);
        tvis.item.pszText = display;
        tvis.item.iImage = sfi.iIcon;
        tvis.item.iSelectedImage = sfi.iIcon;
        tvis.item.lParam = (LPARAM)stored;
        tvis.item.cChildren = (fd.dwFileAttributes & FILE_ATTRIBUTE_DIRECTORY) ? 1 : 0;
        
        HTREEITEM hItem = TreeView_InsertItem(hTree, &tvis);
        g_item_paths[hItem] = *stored;
        
        if (tvis.item.cChildren) {
            TVINSERTSTRUCTA dummy = {};
            dummy.hParent = hItem;
            dummy.hInsertAfter = TVI_LAST;
            dummy.item.mask = TVIF_TEXT;
            dummy.item.pszText = (LPSTR)"";
            TreeView_InsertItem(hTree, &dummy);
        }
        
    } while (FindNextFileA(hFind, &fd));
    
    FindClose(hFind);
    TreeView_SortChildren(hTree, hParent, FALSE);
}

static void RefreshNode(HWND hTree, HTREEITEM hItem) {
    if (!TreeView_GetChild(hTree, hItem)) return;
    
    HTREEITEM hChild = TreeView_GetChild(hTree, hItem);
    while (hChild) {
        HTREEITEM hNext = TreeView_GetNextSibling(hTree, hChild);
        TVITEM item = {};
        item.hItem = hChild;
        item.mask = TVIF_PARAM;
        TreeView_GetItem(hTree, &item);
        delete (std::string*)item.lParam;
        TreeView_DeleteItem(hTree, hChild);
        hChild = hNext;
    }
    
    TVITEM item = {};
    item.hItem = hItem;
    item.mask = TVIF_PARAM;
    TreeView_GetItem(hTree, &item);
    
    PopulateTree(hTree, hItem, *(std::string*)item.lParam);
}

static LRESULT CALLBACK ContainerProc(HWND hWnd, UINT uMsg, WPARAM wParam, 
    LPARAM lParam, UINT_PTR uIdSubclass, DWORD_PTR dwRefData) {
    
    switch (uMsg) {
        case WM_NOTIFY: {
            NMHDR* pnmh = (NMHDR*)lParam;
            if (pnmh->idFrom == IDC_CONTAINER && pnmh->code == TVN_ITEMEXPANDING) {
                NMTREEVIEW* pnmtv = (NMTREEVIEW*)lParam;
                if (pnmtv->action == TVE_EXPAND) {
                    RefreshNode(pnmh->hwndFrom, pnmtv->itemNew.hItem);
                }
                return 0;
            }
            if (pnmh->idFrom == IDC_CONTAINER && pnmh->code == NM_DBLCLK) {
                HTREEITEM hSel = TreeView_GetSelection(pnmh->hwndFrom);
                if (hSel) {
                    TVITEM item = {};
                    item.hItem = hSel;
                    item.mask = TVIF_PARAM;
                    TreeView_GetItem(pnmh->hwndFrom, &item);
                    
                    std::string* path = (std::string*)item.lParam;
                    DWORD attr = GetFileAttributesA(path->c_str());
                    
                    if (!(attr & FILE_ATTRIBUTE_DIRECTORY)) {
                        g_oracle.Route(hWnd, CAP_DISPLAY, (void*)path->c_str());
                    }
                }
                return 0;
            }
            break;
        }
        
        case WM_CONTEXTMENU: {
            POINT pt = {(int)(short)LOWORD(lParam), (int)(short)HIWORD(lParam)};
            if (pt.x == -1 && pt.y == -1) {
                RECT rc;
                HTREEITEM hSel = TreeView_GetSelection(hWnd);
                if (hSel) {
                    TreeView_GetItemRect(hWnd, hSel, &rc, TRUE);
                    pt.x = rc.left;
                    pt.y = rc.bottom;
                    ClientToScreen(hWnd, &pt);
                }
            }
            
            HTREEITEM hSel = TreeView_GetSelection(hWnd);
            if (!hSel) break;
            
            TVITEM item = {};
            item.hItem = hSel;
            item.mask = TVIF_PARAM;
            TreeView_GetItem(hWnd, &item);
            
            std::string* path = (std::string*)item.lParam;
            char current_dir[MAX_PATH];
            GetCurrentDirectoryA(MAX_PATH, current_dir);
            
            HMENU hMenu = CreatePopupMenu();
            AppendMenuA(hMenu, MF_STRING, IDM_EXECUTE, "\xE2\x96\xB6 Open");
            AppendMenuA(hMenu, MF_SEPARATOR, 0, nullptr);
            AppendMenuA(hMenu, MF_STRING, IDM_REVEAL, "\xF0\x9F\x93\x82 Reveal");
            AppendMenuA(hMenu, MF_STRING, IDM_COPYPATH, "\xE2\x8C\x98 Full Path");
            AppendMenuA(hMenu, MF_STRING, IDM_COPYREL, "\xE2\x86\xB3 Relative");
            
            int cmd = TrackPopupMenu(hMenu, TPM_RETURNCMD | TPM_NONOTIFY, 
                pt.x, pt.y, 0, hWnd, nullptr);
            DestroyMenu(hMenu);
            
            if (cmd == IDM_REVEAL) {
                std::string param = "/select,\"" + *path + "\"";
                ShellExecuteA(nullptr, "open", "explorer.exe", 
                    param.c_str(), nullptr, SW_SHOWNORMAL);
            }
            else if (cmd == IDM_COPYPATH) {
                size_t len = path->length() + 1;
                HGLOBAL hMem = GlobalAlloc(GMEM_MOVEABLE, len);
                if (hMem) {
                    memcpy(GlobalLock(hMem), path->c_str(), len);
                    GlobalUnlock(hMem);
                    OpenClipboard(nullptr);
                    EmptyClipboard();
                    SetClipboardData(CF_TEXT, hMem);
                    CloseClipboard();
                }
            }
            else if (cmd == IDM_COPYREL) {
                std::string rel = path->substr(strlen(current_dir) + 1);
                size_t len = rel.length() + 1;
                HGLOBAL hMem = GlobalAlloc(GMEM_MOVEABLE, len);
                if (hMem) {
                    memcpy(GlobalLock(hMem), rel.c_str(), len);
                    GlobalUnlock(hMem);
                    OpenClipboard(nullptr);
                    EmptyClipboard();
                    SetClipboardData(CF_TEXT, hMem);
                    CloseClipboard();
                }
            }
            else if (cmd == IDM_EXECUTE) {
                DWORD attr = GetFileAttributesA(path->c_str());
                if (attr & FILE_ATTRIBUTE_DIRECTORY) {
                    TreeView_Expand(hWnd, hSel, TVE_TOGGLE);
                } else {
                    ShellExecuteA(nullptr, "open", path->c_str(), 
                        nullptr, nullptr, SW_SHOWNORMAL);
                }
            }
            return 0;
        }
    }
    
    return DefSubclassProc(hWnd, uMsg, wParam, lParam);
}

