#include "α.hpp"

#define IDC_ROUTER 0x4000
#define ID_CMD_BASE 0x5000

static std::map<UINT, Capability> g_command_caps;
static std::map<UINT, std::function<void()>> g_command_handlers;
static HWND g_router_hwnd = nullptr;

static const char* CapIcon(Capability c) {
    if (c & CAP_CONTAINER) return "\xF0\x9F\x93\x81";
    if (c & CAP_DISPLAY) return "\xF0\x9F\x93\x84";
    if (c & CAP_MANIPULATE) return "\xE2\x9C\x8F";
    if (c & CAP_PERSIST) return "\xF0\x9F\x92\xBE";
    if (c & CAP_NAVIGATE) return "\xF0\x9F\xA7\xAD";
    if (c & CAP_ROUTE) return "\xE2\x86\x97";
    return "\xE2\x97\x8F";
}

static void RegisterBuiltins() {
    UINT id = ID_CMD_BASE;
    
    g_command_caps[id] = CAP_CONTAINER | 0x1;
    g_command_handlers[id] = []() {
        char path[MAX_PATH];
        GetCurrentDirectoryA(MAX_PATH, path);
        std::string new_path = std::string(path) + "\\new_" + std::to_string(GetTickCount());
        CreateDirectoryA(new_path.c_str(), nullptr);
        if (g_container_hwnd) {
            HTREEITEM hRoot = TreeView_GetRoot(g_container_hwnd);
            if (hRoot) RefreshNode(g_container_hwnd, hRoot);
        }
    };
    id++;
    
    g_command_caps[id] = CAP_DISPLAY | 0x1;
    g_command_handlers[id] = []() {
        OPENFILENAMEA ofn = {};
        char file[MAX_PATH] = {};
        ofn.lStructSize = sizeof(ofn);
        ofn.hwndOwner = g_router_hwnd;
        ofn.lpstrFile = file;
        ofn.nMaxFile = MAX_PATH;
        ofn.Flags = OFN_FILEMUSTEXIST;
        if (GetOpenFileNameA(&ofn)) {
            ShellExecuteA(nullptr, "open", file, nullptr, nullptr, SW_SHOWNORMAL);
        }
    };
    id++;
    
    g_command_caps[id] = CAP_PERSIST | 0x1;
    g_command_handlers[id] = []() {
        g_oracle.Route(g_router_hwnd, CAP_MANIPULATE, (void*)"settings");
    };
    id++;
    
    g_command_caps[id] = CAP_ROUTE | 0x1;
    g_command_handlers[id] = []() {
        PostQuitMessage(0);
    };
    id++;
}

std::shared_ptr<Node> Manifest_γ(HWND parent, Oracle& oracle) {
    auto node = oracle.Manifest(CAP_ROUTE | CAP_CONTAINER, parent);
    
    RegisterBuiltins();
    
    HMENU hMenu = CreateMenu();
    
    std::map<Capability, std::vector<UINT>> groups;
    for (auto& [id, caps] : g_command_caps) {
        Capability group = caps & 0xFFFFFFFFFFFFFFF0;
        groups[group].push_back(id);
    }
    
    for (auto& [group, ids] : groups) {
        HMENU hSub = CreatePopupMenu();
        for (UINT id : ids) {
            std::string entry = std::string(CapIcon(g_command_caps[id])) + " ";
            entry += std::to_string(id - ID_CMD_BASE);
            AppendMenuA(hSub, MF_STRING, id, entry.c_str());
        }
        AppendMenuA(hMenu, MF_POPUP, (UINT_PTR)hSub, CapIcon(group));
    }
    
    SetMenu(parent, hMenu);
    
    g_router_hwnd = parent;
    node->handle = (void*)hMenu;
    
    return node;
}

void ExecuteCommand(UINT cmd) {
    auto it = g_command_handlers.find(cmd);
    if (it != g_command_handlers.end()) {
        it->second();
    }
}
