#include "α.hpp"

#define IDC_SETTINGS 0x6000
#define ID_SETTING_BASE 0x7000

static HWND g_settings_hwnd = nullptr;
static std::map<uint32_t, HWND> g_setting_controls;

static uint32_t HashString(const char* s) {
    uint32_t hash = 0x811c9dc5;
    while (*s) {
        hash ^= (uint8_t)*s++;
        hash *= 0x01000193;
    }
    return hash;
}

static uint32_t GetSetting(uint32_t hash, uint32_t default_val) {
    HKEY hKey;
    uint32_t val = default_val;
    DWORD size = sizeof(val);
    if (RegOpenKeyExA(HKEY_CURRENT_USER, "Software\\R", 0, KEY_READ, &hKey) == ERROR_SUCCESS) {
        RegQueryValueExA(hKey, (char*)&hash, nullptr, nullptr, (BYTE*)&val, &size);
        RegCloseKey(hKey);
    }
    return val;
}

static void SetSetting(uint32_t hash, uint32_t val) {
    HKEY hKey;
    if (RegCreateKeyExA(HKEY_CURRENT_USER, "Software\\R", 0, nullptr, 
        0, KEY_WRITE, nullptr, &hKey, nullptr) == ERROR_SUCCESS) {
        RegSetValueExA(hKey, (char*)&hash, 0, REG_DWORD, (BYTE*)&val, sizeof(val));
        RegCloseKey(hKey);
    }
}

static LRESULT CALLBACK SettingsProc(HWND hWnd, UINT uMsg, WPARAM wParam,
    LPARAM lParam, UINT_PTR uIdSubclass, DWORD_PTR dwRefData) {
    
    if (uMsg == WM_COMMAND) {
        UINT id = LOWORD(wParam);
        if (id >= ID_SETTING_BASE && id < ID_SETTING_BASE + 100) {
            uint32_t hash = (uint32_t)dwRefData;
            HWND hCtrl = g_setting_controls[hash];
            
            if (hCtrl) {
                uint32_t val = 0;
                char className[256];
                GetClassNameA(hCtrl, className, 256);
                
                if (strcmp(className, "Button") == 0) {
                    val = (Button_GetCheck(hCtrl) == BST_CHECKED) ? 1 : 0;
                } else if (strcmp(className, "Edit") == 0) {
                    char buf[256];
                    GetWindowTextA(hCtrl, buf, 256);
                    val = (uint32_t)atoi(buf);
                }
                
                SetSetting(hash, val);
            }
            return 0;
        }
    }
    
    return DefSubclassProc(hWnd, uMsg, wParam, lParam);
}

