        0, 0, 300, 600, parent, (HMENU)IDC_SETTINGS,
        GetModuleHandle(nullptr), nullptr
    );
    
    struct SettingDef {
        uint32_t hash;
        uint32_t default_val;
        uint32_t min_val;
        uint32_t max_val;
        DWORD style;
        const char* glyph;
    };
    
    SettingDef defs[] = {
        {HashString("enable_stream"), 1, 0, 1, BS_AUTOCHECKBOX, "\xE2\x96\xB6"},
        {HashString("font_scale"), 12, 8, 32, ES_NUMBER, "\xF0\x9F\x94\xA0"},
        {HashString("cache_size"), 64, 16, 512, ES_NUMBER, "\xF0\x9F\x92\xBE"},
        {HashString("auto_nav"), 1, 0, 1, BS_AUTOCHECKBOX, "\xF0\x9F\xA7\xAD"},
    };
    
    int y = 20;
    for (auto& def : defs) {
        uint32_t current = GetSetting(def.hash, def.default_val);
        
        HWND hLabel = CreateWindowExA(
            0, "STATIC", def.glyph,
            WS_CHILD | WS_VISIBLE | SS_CENTERIMAGE,
            20, y, 30, 24, hPanel, nullptr,
            GetModuleHandle(nullptr), nullptr
        );
        
        HWND hCtrl;
        if (def.style == BS_AUTOCHECKBOX) {
            hCtrl = CreateWindowExA(
                0, "BUTTON", "",
                WS_CHILD | WS_VISIBLE | def.style,
                60, y, 200, 24, hPanel, (HMENU)(ID_SETTING_BASE + (y/40)),
                GetModuleHandle(nullptr), nullptr
            );
            Button_SetCheck(hCtrl, current ? BST_CHECKED : BST_UNCHECKED);
        } else {
            hCtrl = CreateWindowExA(
                WS_EX_CLIENTEDGE, "EDIT", std::to_string(current).c_str(),
                WS_CHILD | WS_VISIBLE | def.style,
                60, y, 200, 24, hPanel, (HMENU)(ID_SETTING_BASE + (y/40)),
                GetModuleHandle(nullptr), nullptr
            );
        }
        
        g_setting_controls[def.hash] = hCtrl;
        SetWindowSubclass(hCtrl, SettingsProc, 0, (DWORD_PTR)def.hash);
        
        y += 40;
    }
    
    SetWindowSubclass(hPanel, SettingsProc, 0, 0);
    
    node->handle = hPanel;
    g_settings_hwnd = hPanel;
    
    node->on_resize = [hPanel](int w, int h) {
        SetWindowPos(hPanel, nullptr, w - 300, 24, 300, h - 48, SWP_NOZORDER);
    };
    
    node->on_activate = [](void* data) {
        ShowWindow(g_settings_hwnd, 
            IsWindowVisible(g_settings_hwnd) ? SW_HIDE : SW_SHOW);
    };
    
    return node;
}
