                    W - 550, H - 48, SWP_NOZORDER);
            }
            
            if (g_status_hwnd) {
                SetWindowPos(g_status_hwnd, nullptr, 0, H - 24, W, 24, SWP_NOZORDER);
            }
            
            return 0;
        }
        
        case WM_COMMAND: {
            UINT cmd = LOWORD(wParam);
            if (cmd >= 0x5000 && cmd < 0x6000) {
                ExecuteCommand(cmd);
            }
            return 0;
        }
        
        case WM_DESTROY: {
            PostQuitMessage(0);
            return 0;
        }
    }
    
    return DefWindowProcA(hWnd, uMsg, wParam, lParam);
}

