// =============================================================================
// σ.hpp - Schematic engine (Production)
// =============================================================================
#pragma once
#include <windows.h>
#include <vector>
#include <string>
#include <map>
#include <fstream>
#include <sstream>
#include <algorithm>

#pragma comment(lib, "gdi32.lib")

struct SchematicNode {
    RECT bounds;
    COLORREF color;
    uint32_t cap_hash;
    std::string label;
    std::vector<size_t> inputs;
    std::vector<size_t> outputs;
    bool is_highlighted;
};

struct SchematicWire {
    POINT from;
    POINT to;
    COLORREF color;
    uint32_t cap_type;
};

class SchematicEngine {
    std::vector<SchematicNode> nodes_;
    std::vector<SchematicWire> wires_;
    HDC mem_dc_;
    HBITMAP mem_bmp_;
    int width_, height_;
    
public:
    SchematicEngine(int w, int h) : width_(w), height_(h) {
        HDC screen = GetDC(nullptr);
        mem_dc_ = CreateCompatibleDC(screen);
        mem_bmp_ = CreateCompatibleBitmap(screen, w, h);
        SelectObject(mem_dc_, mem_bmp_);
        ReleaseDC(nullptr, screen);
    }
    
    ~SchematicEngine() {
        DeleteObject(mem_bmp_);
        DeleteDC(mem_dc_);
    }
    
    void AddNode(const RECT& rc, COLORREF col, uint32_t caps, const char* lbl) {
        SchematicNode n;
        n.bounds = rc;
        n.color = col;
        n.cap_hash = caps;
        n.label = lbl;
        n.is_highlighted = false;
        nodes_.push_back(n);
    }
    
    void AddWire(POINT a, POINT b, COLORREF col, uint32_t cap) {
        SchematicWire w;
        w.from = a;
        w.to = b;
        w.color = col;
        w.cap_type = cap;
        wires_.push_back(w);
    }
    
    void Render() {
        // Background
        RECT bg = {0, 0, width_, height_};
        FillRect(mem_dc_, &bg, (HBRUSH)GetStockObject(WHITE_BRUSH));
        
        // Grid
        HPEN grid_pen = CreatePen(PS_DOT, 1, RGB(230, 230, 230));
        SelectObject(mem_dc_, grid_pen);
        for (int x = 0; x < width_; x += 20) {
            MoveToEx(mem_dc_, x, 0, nullptr);
            LineTo(mem_dc_, x, height_);
        }
        for (int y = 0; y < height_; y += 20) {
            MoveToEx(mem_dc_, 0, y, nullptr);
            LineTo(mem_dc_, width_, y);
        }
        DeleteObject(grid_pen);
        
        // Wires
        for (auto& w : wires_) {
            HPEN pen = CreatePen(PS_SOLID, 2, w.color);
            SelectObject(mem_dc_, pen);
            MoveToEx(mem_dc_, w.from.x, w.from.y, nullptr);
            LineTo(mem_dc_, w.to.x, w.to.y);
            DeleteObject(pen);
            
            // Arrowhead
            double angle = atan2(w.to.y - w.from.y, w.to.x - w.from.x);
            POINT arrow[3];
            arrow[0] = w.to;
            arrow[1].x = w.to.x - 10 * cos(angle - 0.5);
            arrow[1].y = w.to.y - 10 * sin(angle - 0.5);
            arrow[2].x = w.to.x - 10 * cos(angle + 0.5);
            arrow[2].y = w.to.y - 10 * sin(angle + 0.5);
            Polygon(mem_dc_, arrow, 3);
        }
        
        // Nodes
        for (auto& n : nodes_) {
            HBRUSH brush = CreateSolidBrush(n.color);
            HBRUSH old = (HBRUSH)SelectObject(mem_dc_, brush);
            
            if (n.is_highlighted) {
                HPEN pen = CreatePen(PS_SOLID, 3, RGB(255, 0, 0));
                SelectObject(mem_dc_, pen);
                Rectangle(mem_dc_, n.bounds.left, n.bounds.top, 
                    n.bounds.right, n.bounds.bottom);
                DeleteObject(pen);
            } else {
                Rectangle(mem_dc_, n.bounds.left, n.bounds.top, 
                    n.bounds.right, n.bounds.bottom);
            }
            
            SelectObject(mem_dc_, old);
            DeleteObject(brush);
            
            // Label
            SetBkMode(mem_dc_, TRANSPARENT);
            SetTextColor(mem_dc_, RGB(0, 0, 0));
            DrawTextA(mem_dc_, n.label.c_str(), -1, (RECT*)&n.bounds, 
                DT_CENTER | DT_VCENTER | DT_SINGLELINE);
        }
        
        // Legend
        RECT leg = {10, 10, 200, 150};
        FillRect(mem_dc_, &leg, (HBRUSH)GetStockObject(LTGRAY_BRUSH));
        FrameRect(mem_dc_, &leg, (HBRUSH)GetStockObject(BLACK_BRUSH));
        
        SetTextColor(mem_dc_, RGB(0, 0, 0));
        TextOutA(mem_dc_, 20, 20, "CAPABILITIES:", 13);
        
        struct { COLORREF c; const char* n; } legend[] = {
            {RGB(100, 149, 237), "CONTAINER"},
            {RGB(144, 238, 144), "NAVIGATE"},
            {RGB(255, 182, 193), "DISPLAY"},
            {RGB(255, 255, 224), "MANIPULATE"},
            {RGB(221, 160, 221), "ROUTE"},
            {RGB(255, 218, 185), "PERSIST"}
        };
        
        for (int i = 0; i < 6; i++) {
            RECT r = {20, 40 + i*18, 40, 56 + i*18};
            FillRect(mem_dc_, &r, CreateSolidBrush(legend[i].c));
            TextOutA(mem_dc_, 45, 40 + i*18, legend[i].n, strlen(legend[i].n));
        }
    }
    
    bool SaveBMP(const char* filename) {
        BITMAPFILEHEADER bfh;
        BITMAPINFOHEADER bih;
        BITMAP bmp;
        
        GetObject(mem_bmp_, sizeof(bmp), &bmp);
        
        int row_size = ((bmp.bmWidth * 3 + 3) & ~3);
        std::vector<BYTE> bits(row_size * bmp.bmHeight);
        
        BITMAPINFO bi = {};
        bi.bmiHeader.biSize = sizeof(BITMAPINFOHEADER);
        bi.bmiHeader.biWidth = bmp.bmWidth;
        bi.bmiHeader.biHeight = -bmp.bmHeight;
        bi.bmiHeader.biPlanes = 1;
        bi.bmiHeader.biBitCount = 24;
        bi.bmiHeader.biCompression = BI_RGB;
        
        GetDIBits(mem_dc_, mem_bmp_, 0, bmp.bmHeight, bits.data(), &bi, DIB_RGB_COLORS);
        
        bfh.bfType = 0x4D42;
        bfh.bfSize = sizeof(bfh) + sizeof(bih) + bits.size();
        bfh.bfReserved1 = 0;
        bfh.bfReserved2 = 0;
        bfh.bfOffBits = sizeof(bfh) + sizeof(bih);
        
        bih.biSize = sizeof(bih);
        bih.biWidth = bmp.bmWidth;
        bih.biHeight = bmp.bmHeight;
        bih.biPlanes = 1;
        bih.biBitCount = 24;
        bih.biCompression = BI_RGB;
        bih.biSizeImage = bits.size();
        bih.biXPelsPerMeter = 2835;
        bih.biYPelsPerMeter = 2835;
        bih.biClrUsed = 0;
        bih.biClrImportant = 0;
        
        std::ofstream f(filename, std::ios::binary);
        if (!f) return false;
        
        f.write((char*)&bfh, sizeof(bfh));
        f.write((char*)&bih, sizeof(bih));
        f.write((char*)bits.data(), bits.size());
        
        return f.good();
    }
    
    bool SaveSVG(const char* filename) {
        std::ofstream f(filename);
        if (!f) return false;
        
        f << "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n";
        f << "<svg width=\"" << width_ << "\" height=\"" << height_ 
          << "\" xmlns=\"http://www.w3.org/2000/svg\">\n";
        f << "<rect width=\"100%\" height=\"100%\" fill=\"white\"/>\n";
        
        // Grid
        f << "<g stroke=\"#eee\" stroke-width=\"1\">\n";
        for (int x = 0; x < width_; x += 20) {
            f << "<line x1=\"" << x << "\" y1=\"0\" x2=\"" << x << "\" y2=\"" << height_ << "\"/>\n";
        }
        for (int y = 0; y < height_; y += 20) {
            f << "<line x1=\"0\" y1=\"" << y << "\" x2=\"" << width_ << "\" y2=\"" << y << "\"/>\n";
        }
        f << "</g>\n";
        
        // Wires
        for (auto& w : wires_) {
            f << "<line x1=\"" << w.from.x << "\" y1=\"" << w.from.y 
              << "\" x2=\"" << w.to.x << "\" y2=\"" << w.to.y 
              << "\" stroke=\"#" << std::hex << ((w.color >> 16) & 0xFF) 
              << ((w.color >> 8) & 0xFF) << (w.color & 0xFF) 
              << std::dec << "\" stroke-width=\"2\" marker-end=\"url(#arrow)\"/>\n";
        }
        
        f << "<defs><marker id=\"arrow\" markerWidth=\"10\" markerHeight=\"10\" "
           << "refX=\"9\" refY=\"3\" orient=\"auto\" markerUnits=\"strokeWidth\">"
           << "<path d=\"M0,0 L0,6 L9,3 z\" fill=\"#333\"/></marker></defs>\n";
        
        // Nodes
        for (auto& n : nodes_) {
            int w = n.bounds.right - n.bounds.left;
            int h = n.bounds.bottom - n.bounds.top;
            
            f << "<rect x=\"" << n.bounds.left << "\" y=\"" << n.bounds.top 
              << "\" width=\"" << w << "\" height=\"" << h 
              << "\" fill=\"#" << std::hex << ((n.color >> 16) & 0xFF) 
              << ((n.color >> 8) & 0xFF) << (n.color & 0xFF) << std::dec 
              << "\" stroke=\"black\" stroke-width=\"" 
              << (n.is_highlighted ? "3" : "1") << "\"/>\n";
            
            f << "<text x=\"" << (n.bounds.left + w/2) << "\" y=\"" 
              << (n.bounds.top + h/2 + 5) << "\" text-anchor=\"middle\" "
              << "font-family=\"Arial\" font-size=\"12\">" << n.label << "</text>\n";
        }
        
        f << "</svg>\n";
        return f.good();
    }
    
    void HighlightNode(size_t idx) {
        if (idx < nodes_.size()) {
            for (auto& n : nodes_) n.is_highlighted = false;
            nodes_[idx].is_highlighted = true;
        }
    }
    
    size_t HitTest(int x, int y) {
        for (size_t i = 0; i < nodes_.size(); i++) {
            if (x >= nodes_[i].bounds.left && x < nodes_[i].bounds.right &&
                y >= nodes_[i].bounds.top && y < nodes_[nodes_.size()].bounds.bottom) {
                return i;
            }
        }
        return (size_t)-1;
    }
    
    void ExportSchematicCode(const char* filename) {
        std::ofstream f(filename);
        if (!f) return;
        
        f << "// Auto-generated from schematic\n";
        f << "#pragma once\n\n";
        
        for (size_t i = 0; i < nodes_.size(); i++) {
            auto& n = nodes_[i];
            f << "// NODE " << i << ": " << n.label << "\n";
            f << "#define NODE_" << i << "_CAPS 0x" << std::hex << n.cap_hash << std::dec << "\n";
            f << "#define NODE_" << i << "_X " << n.bounds.left << "\n";
            f << "#define NODE_" << i << "_Y " << n.bounds.top << "\n";
            f << "#define NODE_" << i << "_W " << (n.bounds.right - n.bounds.left) << "\n";
            f << "#define NODE_" << i << "_H " << (n.bounds.bottom - n.bounds.top) << "\n";
            
            if (!n.inputs.empty()) {
                f << "#define NODE_" << i << "_INPUTS {";
                for (size_t j = 0; j < n.inputs.size(); j++) {
                    if (j) f << ",";
                    f << n.inputs[j];
                }
                f << "}\n";
            }
            
            if (!n.outputs.empty()) {
                f << "#define NODE_" << i << "_OUTPUTS {";
                for (size_t j = 0; j < n.outputs.size(); j++) {
                    if (j) f << ",";
                    f << n.outputs[j];
                }
                f << "}\n";
            }
            f << "\n";
        }
    }
};

