class SchematicParser {
public:
    struct ParsedNode {
        uint32_t caps;
        int x, y, w, h;
        std::string label;
        std::vector<size_t> inputs;
        std::vector<size_t> outputs;
    };
    
    std::vector<ParsedNode> Parse(const char* filename) {
        std::vector<ParsedNode> result;
        std::ifstream f(filename);
        if (!f) return result;
        
        std::string line;
        ParsedNode current;
        bool in_node = false;
        
        while (std::getline(f, line)) {
            if (line.find("// NODE") != std::string::npos) {
                if (in_node) result.push_back(current);
                current = {};
                in_node = true;
                
                size_t name_start = line.find(": ");
                if (name_start != std::string::npos) {
                    current.label = line.substr(name_start + 2);
                }
            }
            else if (line.find("_CAPS") != std::string::npos) {
                sscanf(line.c_str(), "%*s 0x%x", &current.caps);
            }
            else if (line.find("_X ") != std::string::npos) {
                sscanf(line.c_str(), "%*s %d", &current.x);
            }
            else if (line.find("_Y ") != std::string::npos) {
                sscanf(line.c_str(), "%*s %d", &current.y);
            }
            else if (line.find("_W ") != std::string::npos) {
                sscanf(line.c_str(), "%*s %d", &current.w);
            }
            else if (line.find("_H ") != std::string::npos) {
                sscanf(line.c_str(), "%*s %d", &current.h);
            }
            else if (line.find("_INPUTS") != std::string::npos) {
                size_t start = line.find('{');
                size_t end = line.find('}');
                if (start != std::string::npos && end != std::string::npos) {
                    std::string nums = line.substr(start + 1, end - start - 1);
                    std::stringstream ss(nums);
                    size_t n;
                    while (ss >> n) {
                        current.inputs.push_back(n);
                        if (ss.peek() == ',') ss.ignore();
                    }
                }
            }
            else if (line.find("_OUTPUTS") != std::string::npos) {
                size_t start = line.find('{');
                size_t end = line.find('}');
                if (start != std::string::npos && end != std::string::npos) {
                    std::string nums = line.substr(start + 1, end - start - 1);
                    std::stringstream ss(nums);
                    size_t n;
                    while (ss >> n) {
                        current.outputs.push_back(n);
                        if (ss.peek() == ',') ss.ignore();
                    }
                }
            }
        }
        
        if (in_node) result.push_back(current);
        return result;
    }
    
    std::vector<ParsedNode> ParseSVG(const char* filename) {
        std::vector<ParsedNode> result;
        std::ifstream f(filename);
        if (!f) return result;
        
        std::string content((std::istreambuf_iterator<char>(f)),
                            std::istreambuf_iterator<char>());
        
        // Parse rectangles as nodes
        size_t pos = 0;
        while ((pos = content.find("<rect", pos)) != std::string::npos) {
            ParsedNode node;
            
            size_t x_pos = content.find("x=\"", pos);
            size_t y_pos = content.find("y=\"", pos);
            size_t w_pos = content.find("width=\"", pos);
            size_t h_pos = content.find("height=\"", pos);
            size_t fill_pos = content.find("fill=\"", pos);
            
            if (x_pos != std::string::npos) sscanf(content.c_str() + x_pos, "%*[^\"]\"%d\"", &node.x);
            if (y_pos != std::string::npos) sscanf(content.c_str() + y_pos, "%*[^\"]\"%d\"", &node.y);
            if (w_pos != std::string::npos) sscanf(content.c_str() + w_pos, "%*[^\"]\"%d\"", &node.w);
            if (h_pos != std::string::npos) sscanf(content.c_str() + h_pos, "%*[^\"]\"%d\"", &node.h);
            
            // Color to capability mapping
            if (fill_pos != std::string::npos) {
                char color[8];
                sscanf(content.c_str() + fill_pos, "%*[^\"]\"#%6s\"", color);
                int r, g, b;
                sscanf(color, "%02x%02x%02x", &r, &g, &b);
                
                if (r == 100 && g == 149) node.caps = 0x1;      // CONTAINER
                else if (r == 144 && g == 238) node.caps = 0x2; // NAVIGATE
                else if (r == 255 && g == 182) node.caps = 0x4; // DISPLAY
                else if (r == 255 && g == 255) node.caps = 0x8; // MANIPULATE
                else if (r == 221) node.caps = 0x10;            // ROUTE
                else if (r == 255 && g == 218) node.caps = 0x20; // PERSIST
            }
            
            // Look for text label
            size_t text_pos = content.find("<text", pos);
            size_t text_end = content.find("</text>", text_pos);
            if (text_pos != std::string::npos && text_pos < content.find("<rect", pos + 1)) {
                size_t text_start = content.find(">", text_pos) + 1;
                node.label = content.substr(text_start, text_end - text_start);
            }
            
            result.push_back(node);
            pos++;
        }
        
        return result;
    }
};

