                size_t hit = self->engine_.HitTest(x, y);
                if (hit != (size_t)-1) {
                    self->engine_.HighlightNode(hit);
                    self->dirty_ = true;
                    InvalidateRect(hWnd, nullptr, FALSE);
                }
                return 0;
            }
            
            case WM_KEYDOWN: {
                if (wParam == 'S' && GetAsyncKeyState(VK_CONTROL)) {
                    self->Export("schematic.bmp", "schematic.svg", "schematic.h");
                }
                return 0;
            }
            
            case WM_DESTROY: {
                return 0;
            }
        }
        
        return DefWindowProcA(hWnd, uMsg, wParam, lParam);
    }
    
    HDC GetDC() { return engine_.mem_dc_; }
};

