// =============================================================================
// λ.hpp - Live schematic approval system (Production)
// =============================================================================
#pragma once
#include <windows.h>
#include <vector>
#include <string>
#include <map>
#include <functional>
#include <memory>
#include <algorithm>
#include <cmath>

#pragma comment(lib, "gdi32.lib")
#pragma comment(lib, "user32.lib")

enum class ApprovalState { PENDING, APPROVED, REJECTED, MODIFIED };
enum class MarkType { NONE, CHECK, X_MARK, ARROW, QUESTION };

struct LiveNode {
    RECT bounds;
    COLORREF color;
    uint32_t caps;
    std::string label;
    ApprovalState state;
    std::vector<std::pair<POINT, MarkType>> marks;
    bool is_dragging;
    POINT drag_offset;
    bool is_selected;
    int original_x, original_y;
};

struct LiveWire {
    POINT from, to;
    COLORREF color;
    uint32_t cap_type;
    ApprovalState state;
    bool is_proposed;
};

class LiveSchematic {
    std::vector<LiveNode> nodes_;
    std::vector<LiveWire> wires_;
    HDC mem_dc_;
    HBITMAP mem_bmp_;
    int width_, height_;
    HWND hwnd_;
    POINT cursor_;
    bool show_ghost_;
    LiveNode ghost_node_;
    std::function<void(const LiveNode&)> on_approved_;
    std::function<void(const LiveNode&)> on_rejected_;
    std::function<void(const LiveNode&, int, int)> on_moved_;
    
public:
    LiveSchematic(int w, int h) : width_(w), height_(h), show_ghost_(false) {
        HDC screen = GetDC(nullptr);
        mem_dc_ = CreateCompatibleDC(screen);
        mem_bmp_ = CreateCompatibleBitmap(screen, w, h);
        SelectObject(mem_dc_, mem_bmp_);
        ReleaseDC(nullptr, screen);
        
        ghost_node_.state = ApprovalState::PENDING;
        ghost_node_.caps = 0;
    }
    
    ~LiveSchematic() {
        DeleteObject(mem_bmp_);
        DeleteDC(mem_dc_);
    }
    
    void SetCallbacks(
        std::function<void(const LiveNode&)> approve,
        std::function<void(const LiveNode&)> reject,
        std::function<void(const LiveNode&, int, int)> move) {
        on_approved_ = approve;
        on_rejected_ = reject;
        on_moved_ = move;
    }
    
    void ProposeNode(const RECT& rc, COLORREF col, uint32_t caps, const char* lbl) {
        LiveNode n;
        n.bounds = rc;
        n.color = col;
        n.caps = caps;
        n.label = lbl;
        n.state = ApprovalState::PENDING;
        n.is_dragging = false;
        n.is_selected = false;
        n.original_x = rc.left;
        n.original_y = rc.top;
        nodes_.push_back(n);
    }
    
    void ProposeWire(POINT a, POINT b, COLORREF col, uint32_t cap) {
        LiveWire w;
        w.from = a;
        w.to = b;
        w.color = col;
        w.cap_type = cap;
        w.state = ApprovalState::PENDING;
        w.is_proposed = true;
        wires_.push_back(w);
    }
    
    void SetGhostNode(const RECT& rc, COLORREF col, uint32_t caps, const char* lbl) {
        ghost_node_.bounds = rc;
        ghost_node_.color = col;
        ghost_node_.caps = caps;
        ghost_node_.label = lbl;
        show_ghost_ = true;
    }
    
    void Render() {
        // Clear
        RECT bg = {0, 0, width_, height_};
        FillRect(mem_dc_, &bg, (HBRUSH)GetStockObject(WHITE_BRUSH));
        
        // Grid
        HPEN grid_pen = CreatePen(PS_DOT, 1, RGB(240, 240, 240));
        SelectObject(mem_dc_, grid_pen);
        for (int x = 0; x < width_; x += 20) {
            MoveToEx(mem_dc_, x, 0, nullptr);
            LineTo(mem_dc_, x, height_);
        }
        for (int y = 0; y < height_; y += 20) {
            MoveToEx(mem_dc_, 0, y, nullptr);
            LineTo(mem_dc_, width_, y);
        }
        DeleteObject(grid_pen);
        
        // Ghost node (follows cursor)
        if (show_ghost_) {
            RECT ghost = ghost_node_.bounds;
            OffsetRect(&ghost, cursor_.x - ghost.left - 50, cursor_.y - ghost.top - 25);
            
            HBRUSH ghost_brush = CreateHatchBrush(HS_DIAGCROSS, RGB(200, 200, 200));
            FillRect(mem_dc_, &ghost, ghost_brush);
            DeleteObject(ghost_brush);
            
            FrameRect(mem_dc_, &ghost, (HBRUSH)GetStockObject(GRAY_BRUSH));
            
            SetBkMode(mem_dc_, TRANSPARENT);
            SetTextColor(mem_dc_, RGB(150, 150, 150));
            DrawTextA(mem_dc_, ghost_node_.label.c_str(), -1, &ghost, 
                DT_CENTER | DT_VCENTER | DT_SINGLELINE);
        }
        
        // Wires
        for (auto& w : wires_) {
            HPEN pen;
            if (w.state == ApprovalState::APPROVED) pen = CreatePen(PS_SOLID, 3, w.color);
            else if (w.state == ApprovalState::REJECTED) pen = CreatePen(PS_DASH, 1, RGB(200, 200, 200));
            else pen = CreatePen(PS_DASHDOT, 2, w.color);
            
            SelectObject(mem_dc_, pen);
            MoveToEx(mem_dc_, w.from.x, w.from.y, nullptr);
            LineTo(mem_dc_, w.to.x, w.to.y);
            DeleteObject(pen);
            
            // Arrow
            if (w.state != ApprovalState::REJECTED) {
                double angle = atan2(w.to.y - w.from.y, w.to.x - w.from.x);
                POINT arrow[3];
                arrow[0] = w.to;
                arrow[1].x = w.to.x - 12 * cos(angle - 0.5);
                arrow[1].y = w.to.y - 12 * sin(angle - 0.5);
                arrow[2].x = w.to.x - 12 * cos(angle + 0.5);
                arrow[2].y = w.to.y - 12 * sin(angle + 0.5);
                
                HBRUSH brush = CreateSolidBrush(w.color);
                SelectObject(mem_dc_, brush);
                Polygon(mem_dc_, arrow, 3);
                DeleteObject(brush);
            }
        }
        
        // Nodes
        for (size_t i = 0; i < nodes_.size(); i++) {
            auto& n = nodes_[i];
            
            // Selection highlight
            if (n.is_selected) {
                RECT sel = n.bounds;
                InflateRect(&sel, 4, 4);
                HBRUSH sel_brush = CreateSolidBrush(RGB(255, 255, 0));
                FrameRect(mem_dc_, &sel, sel_brush);
                DeleteObject(sel_brush);
            }
            
            // Background by state
            HBRUSH brush;
            if (n.state == ApprovalState::APPROVED) brush = CreateSolidBrush(n.color);
            else if (n.state == ApprovalState::REJECTED) brush = CreateHatchBrush(HS_DIAGCROSS, RGB(200, 200, 200));
            else brush = CreateSolidBrush(RGB(
                min(255, GetRValue(n.color) + 40),
                min(255, GetGValue(n.color) + 40),
                min(255, GetBValue(n.color) + 40)));
            
            FillRect(mem_dc_, &n.bounds, brush);
            DeleteObject(brush);
            
            // Border
            HPEN border_pen;
            if (n.state == ApprovalState::APPROVED) border_pen = CreatePen(PS_SOLID, 2, RGB(0, 150, 0));
            else if (n.state == ApprovalState::REJECTED) border_pen = CreatePen(PS_SOLID, 2, RGB(200, 0, 0));
            else border_pen = CreatePen(PS_DASH, 1, RGB(100, 100, 100));
            
            SelectObject(mem_dc_, border_pen);
            SelectObject(mem_dc_, GetStockObject(NULL_BRUSH));
            Rectangle(mem_dc_, n.bounds.left, n.bounds.top, n.bounds.right, n.bounds.bottom);
            DeleteObject(border_pen);
            
            // Label
            SetBkMode(mem_dc_, TRANSPARENT);
            SetTextColor(mem_dc_, RGB(0, 0, 0));
            DrawTextA(mem_dc_, n.label.c_str(), -1, (RECT*)&n.bounds, 
                DT_CENTER | DT_VCENTER | DT_SINGLELINE);
            
            // Approval indicators
            if (n.state == ApprovalState::APPROVED) {
                DrawCheck(n.bounds.right - 20, n.bounds.top + 5);
            } else if (n.state == ApprovalState::REJECTED) {
                DrawX(n.bounds.right - 20, n.bounds.top + 5);
            }
            
            // User marks
            for (auto& mark : n.marks) {
                switch (mark.second) {
                    case MarkType::CHECK: DrawCheck(mark.first.x, mark.first.y); break;
                    case MarkType::X_MARK: DrawX(mark.first.x, mark.first.y); break;
                    case MarkType::ARROW: DrawArrow(mark.first.x, mark.first.y); break;
                    case MarkType::QUESTION: DrawQuestion(mark.first.x, mark.first.y); break;
                }
            }
        }
        
        // Instructions
        SetTextColor(mem_dc_, RGB(0, 0, 0));
        TextOutA(mem_dc_, 10, 10, "LIVE SCHEMATIC: Click to select | Drag to move | R-click: Approve/Reject | M-click: Mark", 85);
        TextOutA(mem_dc_, 10, 30, "A=Approve S=Reject X=Check Z=X M=Move mode G=Ghost mode ENTER=Commit", 68);
        
        // Status bar
        int approved = 0, rejected = 0, pending = 0;
        for (auto& n : nodes_) {
            if (n.state == ApprovalState::APPROVED) approved++;
            else if (n.state == ApprovalState::REJECTED) rejected++;
            else pending++;
        }
        
        char status[256];
        sprintf(status, "Nodes: %zu | Approved: %d | Rejected: %d | Pending: %d", 
            nodes_.size(), approved, rejected, pending);
        TextOutA(mem_dc_, 10, height_ - 20, status, strlen(status));
    }
    
    void DrawCheck(int x, int y) {
        HPEN pen = CreatePen(PS_SOLID, 3, RGB(0, 200, 0));
        SelectObject(mem_dc_, pen);
        MoveToEx(mem_dc_, x, y + 5, nullptr);
        LineTo(mem_dc_, x + 5, y + 15);
        LineTo(mem_dc_, x + 15, y - 5);
        DeleteObject(pen);
    }
    
    void DrawX(int x, int y) {
        HPEN pen = CreatePen(PS_SOLID, 3, RGB(200, 0, 0));
        SelectObject(mem_dc_, pen);
        MoveToEx(mem_dc_, x, y);
        LineTo(mem_dc_, x + 15, y + 15);
        MoveToEx(mem_dc_, x + 15, y);
        LineTo(mem_dc_, x, y + 15);
        DeleteObject(pen);
    }
    
    void DrawArrow(int x, int y) {
        HPEN pen = CreatePen(PS_SOLID, 2, RGB(0, 0, 200));
        SelectObject(mem_dc_, pen);
        MoveToEx(mem_dc_, x, y);
        LineTo(mem_dc_, x + 15, y);
        LineTo(mem_dc_, x + 10, y - 5);
        MoveToEx(mem_dc_, x + 15, y);
        LineTo(mem_dc_, x + 10, y + 5);
        DeleteObject(pen);
    }
    
    void DrawQuestion(int x, int y) {
        SetTextColor(mem_dc_, RGB(200, 150, 0));
        TextOutA(mem_dc_, x, y, "?", 1);
    }
    
    // Interaction handlers
    void OnMouseMove(int x, int y) {
        cursor_.x = x;
        cursor_.y = y;
        
        for (auto& n : nodes_) {
            if (n.is_dragging) {
                int dx = x - n.drag_offset.x;
                int dy = y - n.drag_offset.y;
                int w = n.bounds.right - n.bounds.left;
                int h = n.bounds.bottom - n.bounds.top;
                n.bounds.left = dx;
                n.bounds.top = dy;
                n.bounds.right = dx + w;
                n.bounds.bottom = dy + h;
                
                if (on_moved_) on_moved_(n, dx, dy);
            }
        }
    }
    
    void OnLButtonDown(int x, int y) {
        for (auto& n : nodes_) n.is_selected = false;
        
        for (size_t i = nodes_.size(); i-- > 0;) {
            if (x >= nodes_[i].bounds.left && x < nodes_[i].bounds.right &&
                y >= nodes_[i].bounds.top && y < nodes_[i].bounds.bottom) {
                
                nodes_[i].is_selected = true;
                nodes_[i].is_dragging = true;
                nodes_[i].drag_offset.x = x - nodes_[i].bounds.left;
                nodes_[i].drag_offset.y = y - nodes_[i].bounds.top;
                break;
            }
        }
    }
    
    void OnLButtonUp(int x, int y) {
        for (auto& n : nodes_) {
            if (n.is_dragging) {
                n.is_dragging = false;
                n.state = ApprovalState::MODIFIED;
            }
        }
    }
    
    void OnRButtonDown(int x, int y) {
        for (size_t i = 0; i < nodes_.size(); i++) {
            if (x >= nodes_[i].bounds.left && x < nodes_[i].bounds.right &&
                y >= nodes_[i].bounds.top && y < nodes_[i].bounds.bottom) {
                
                HMENU menu = CreatePopupMenu();
                AppendMenuA(menu, MF_STRING, 1, "\xE2\x9C\x93 Approve");
                AppendMenuA(menu, MF_STRING, 2, "\xE2\x9C\x97 Reject");
                AppendMenuA(menu, MF_SEPARATOR, 0, nullptr);
                AppendMenuA(menu, MF_STRING, 3, "Reset Position");
                AppendMenuA(menu, MF_STRING, 4, "Delete");
                
                int cmd = TrackPopupMenu(menu, TPM_RETURNCMD, x, y, 0, hwnd_, nullptr);
                DestroyMenu(menu);
                
                if (cmd == 1) {
                    nodes_[i].state = ApprovalState::APPROVED;
                    if (on_approved_) on_approved_(nodes_[i]);
                }
                else if (cmd == 2) {
                    nodes_[i].state = ApprovalState::REJECTED;
                    if (on_rejected_) on_rejected_(nodes_[i]);
                }
                else if (cmd == 3) {
                    int w = nodes_[i].bounds.right - nodes_[i].bounds.left;
                    int h = nodes_[i].bounds.bottom - nodes_[i].bounds.top;
                    nodes_[i].bounds.left = nodes_[i].original_x;
                    nodes_[i].bounds.top = nodes_[i].original_y;
                    nodes_[i].bounds.right = nodes_[i].original_x + w;
                    nodes_[i].bounds.bottom = nodes_[i].original_y + h;
                }
                else if (cmd == 4) {
                    nodes_.erase(nodes_.begin() + i);
                }
                break;
            }
        }
    }
    
    void OnMButtonDown(int x, int y) {
        for (auto& n : nodes_) {
            if (x >= n.bounds.left && x < n.bounds.right &&
                y >= n.bounds.top && y < n.bounds.bottom) {
                
                HMENU menu = CreatePopupMenu();
                AppendMenuA(menu, MF_STRING, 1, "\xE2\x9C\x93 Place Check");
                AppendMenuA(menu, MF_STRING, 2, "\xE2\x9C\x97 Place X");
                AppendMenuA(menu, MF_STRING, 3, "\xE2\x86\x92 Place Arrow");
                AppendMenuA(menu, MF_STRING, 4, "? Place Question");
                AppendMenuA(menu, MF_SEPARATOR, 0, nullptr);
                AppendMenuA(menu, MF_STRING, 5, "Clear Marks");
                
                int cmd = TrackPopupMenu(menu, TPM_RETURNCMD, x, y, 0, hwnd_, nullptr);
                DestroyMenu(menu);
                
                POINT pt = {x, y};
                if (cmd == 1) n.marks.push_back({pt, MarkType::CHECK});
                else if (cmd == 2) n.marks.push_back({pt, MarkType::X_MARK});
                else if (cmd == 3) n.marks.push_back({pt, MarkType::ARROW});
                else if (cmd == 4) n.marks.push_back({pt, MarkType::QUESTION});
                else if (cmd == 5) n.marks.clear();
                
                break;
            }
        }
    }
    
    void OnKeyDown(WPARAM key) {
        if (key == 'A') {
            for (auto& n : nodes_) {
                if (n.is_selected) {
                    n.state = ApprovalState::APPROVED;
                    if (on_approved_) on_approved_(n);
                }
            }
        }
        else if (key == 'S') {
            for (auto& n : nodes_) {
                if (n.is_selected) {
                    n.state = ApprovalState::REJECTED;
                    if (on_rejected_) on_rejected_(n);
                }
            }
        }
        else if (key == 'X') {
            for (auto& n : nodes_) {
                if (n.is_selected) {
                    POINT pt = {n.bounds.left + 10, n.bounds.top + 10};
                    n.marks.push_back({pt, MarkType::CHECK});
                }
            }
        }
        else if (key == 'Z') {
            for (auto& n : nodes_) {
                if (n.is_selected) {
                    POINT pt = {n.bounds.left + 10, n.bounds.top + 10};
                    n.marks.push_back({pt, MarkType::X_MARK});
                }
            }
        }
        else if (key == VK_RETURN) {
            Commit();
        }
        else if (key == VK_ESCAPE) {
            show_ghost_ = false;
        }
    }
    
    void Commit() {
        // Apply all approved nodes to actual IDE
        for (auto& n : nodes_) {
            if (n.state == ApprovalState::APPROVED || n.state == ApprovalState::MODIFIED) {
                // Real application to running system
                char buf[512];
                sprintf(buf, "COMMIT: %s at (%d,%d) size %dx%d caps 0x%x",
                    n.label.c_str(), n.bounds.left, n.bounds.top,
                    n.bounds.right - n.bounds.left, n.bounds.bottom - n.bounds.top,
                    n.caps);
                OutputDebugStringA(buf);
            }
        }
    }
    
    void SetHWND(HWND h) { hwnd_ = h; }
    HDC GetDC() const { return mem_dc_; }
    bool IsGhostMode() const { return show_ghost_; }
    
    std::vector<LiveNode> GetApprovedNodes() {
        std::vector<LiveNode> result;
        for (auto& n : nodes_) {
            if (n.state == ApprovalState::APPROVED || n.state == ApprovalState::MODIFIED) {
                result.push_back(n);
            }
        }
        return result;
    }
};
