#include "λ.hpp"

class LiveIDEController {
    LiveSchematic schematic_;
    HWND viewer_hwnd_;
    HWND ide_hwnd_;
    bool committed_;
    
public:
    LiveIDEController() : schematic_(1200, 800), committed_(false) {}
    
    void Initialize(HWND ide_window) {
        ide_hwnd_ = ide_window;
        
        // Propose initial layout
        RECT root = {500, 20, 700, 60};
        schematic_.ProposeNode(root, RGB(200, 200, 200), 0, "ROOT");
        
        RECT beta = {50, 200, 250, 400};
        schematic_.ProposeNode(beta, RGB(100, 149, 237), 0x3, "β-CONTAINER");
        
        RECT gamma = {400, 100, 800, 140};
        schematic_.ProposeNode(gamma, RGB(221, 160, 221), 0x11, "γ-ROUTER");
        
        RECT delta = {950, 200, 1150, 400};
        schematic_.ProposeNode(delta, RGB(255, 218, 185), 0x38, "δ-PERSIST");
        
        RECT disp = {400, 300, 800, 600};
        schematic_.ProposeNode(disp, RGB(255, 182, 193), 0x4, "DISPLAY");
        
        schematic_.ProposeWire({600, 60}, {150, 200}, RGB(100, 149, 237), 0x1);
        schematic_.ProposeWire({600, 60}, {600, 100}, RGB(221, 160, 221), 0x10);
        schematic_.ProposeWire({600, 60}, {1050, 200}, RGB(255, 218, 185), 0x20);
        schematic_.ProposeWire({150, 300}, {400, 450}, RGB(144, 238, 144), 0x2);
        schematic_.ProposeWire({1050, 300}, {800, 450}, RGB(255, 255, 224), 0x8);
        
        // Set up callbacks
        schematic_.SetCallbacks(
            [this](const LiveNode& n) { OnApproved(n); },
            [this](const LiveNode& n) { OnRejected(n); },
            [this](const LiveNode& n, int x, int y) { OnMoved(n, x, y); }
        );
        
        ShowViewer();
    }
    
    void ShowViewer() {
        WNDCLASSA wc = {};
        wc.lpfnWndProc = ViewerProc;
        wc.hInstance = GetModuleHandle(nullptr);
        wc.lpszClassName = "LiveSchematicViewer";
        wc.hCursor = LoadCursor(nullptr, IDC_ARROW);
        wc.hbrBackground = (HBRUSH)GetStockObject(WHITE_BRUSH);
        RegisterClassA(&wc);
        
        viewer_hwnd_ = CreateWindowExA(
            WS_EX_TOOLWINDOW | WS_EX_NOACTIVATE,
            "LiveSchematicViewer", "LIVE APPROVAL",
            WS_POPUP | WS_CAPTION | WS_THICKFRAME | WS_VISIBLE,
            50, 50, 1220, 820,
            ide_hwnd_, nullptr, wc.hInstance, this
        );
        
        schematic_.SetHWND(viewer_hwnd_);
        SetTimer(viewer_hwnd_, 1, 16, nullptr); // 60fps
    }
    
    static LRESULT CALLBACK ViewerProc(HWND hWnd, UINT uMsg, WPARAM wParam, LPARAM lParam) {
        LiveIDEController* self = nullptr;
        if (uMsg == WM_CREATE) {
            self = (LiveIDEController*)((CREATESTRUCT*)lParam)->lpCreateParams;
            SetWindowLongPtr(hWnd, GWLP_USERDATA, (LONG_PTR)self);
        } else {
            self = (LiveIDEController*)GetWindowLongPtr(hWnd, GWLP_USERDATA);
        }
        
        if (!self) return DefWindowProcA(hWnd, uMsg, wParam, lParam);
        
        switch (uMsg) {
            case WM_TIMER: {
                self->schematic_.Render();
                InvalidateRect(hWnd, nullptr, FALSE);
                return 0;
            }
            
            case WM_PAINT: {
                PAINTSTRUCT ps;
                HDC hdc = BeginPaint(hWnd, &ps);
                BitBlt(hdc, 0, 0, 1200, 800, self->schematic_.GetDC(), 0, 0, SRCCOPY);
                EndPaint(hWnd, &ps);
                return 0;
            }
            
            case WM_MOUSEMOVE: {
                self->schematic_.OnMouseMove(LOWORD(lParam), HIWORD(lParam));
                return 0;
            }
            
            case WM_LBUTTONDOWN: {
                self->schematic_.OnLButtonDown(LOWORD(lParam), HIWORD(lParam));
                return 0;
            }
            
            case WM_LBUTTONUP: {
                self->schematic_.OnLButtonUp(LOWORD(lParam), HIWORD(lParam));
                return 0;
            }
            
            case WM_RBUTTONDOWN: {
                self->schematic_.OnRButtonDown(LOWORD(lParam), HIWORD(lParam));
                return 0;
            }
            
            case WM_MBUTTONDOWN: {
                self->schematic_.OnMButtonDown(LOWORD(lParam), HIWORD(lParam));
                return 0;
            }
            
            case WM_KEYDOWN: {
                if (wParam == 'G') {
                    // Toggle ghost mode - propose new node at cursor
                    RECT ghost = {0, 0, 100, 50};
                    self->schematic_.SetGhostNode(ghost, RGB(180, 180, 180), 0x40, "NEW");
                }
                else if (wParam == VK_LBUTTON && self->schematic_.IsGhostMode()) {
                    // Place ghost node
                    POINT pt;
                    GetCursorPos(&pt);
                    ScreenToClient(hWnd, &pt);
                    RECT rc = {pt.x - 50, pt.y - 25, pt.x + 50, pt.y + 25};
                    self->schematic_.ProposeNode(rc, RGB(180, 180, 180), 0x40, "NEW");
                }
                else {
                    self->schematic_.OnKeyDown(wParam);
                }
                return 0;
            }
            
            case WM_CLOSE: {
                if (!self->committed_) {
                    int r = MessageBoxA(hWnd, "Commit approved changes before closing?", 
                        "Uncommitted Changes", MB_YESNOCANCEL);
                    if (r == IDYES) {
                        self->schematic_.Commit();
                        self->committed_ = true;
                    } else if (r == IDCANCEL) {
                        return 0;
                    }
                }
                DestroyWindow(hWnd);
                return 0;
            }
            
            case WM_DESTROY: {
                return 0;
            }
        }
        
        return DefWindowProcA(hWnd, uMsg, wParam, lParam);
    }
    
    void OnApproved(const LiveNode& n) {
        // Immediately apply to IDE
        char buf[256];
        sprintf(buf, "APPROVED: %s - applying to IDE", n.label.c_str());
        OutputDebugStringA(buf);
        
        // Real window repositioning
        if (n.label.find("β") != std::string::npos) {
            // Reposition container
            SetWindowPos(GetDlgItem(ide_hwnd_, 0x1000), nullptr,
                n.bounds.left, n.bounds.top + 24,
                n.bounds.right - n.bounds.left,
                n.bounds.bottom - n.bounds.top,
                SWP_NOZORDER);
        }
        else if (n.label.find("δ") != std::string::npos) {
            // Reposition settings
            SetWindowPos(GetDlgItem(ide_hwnd_, 0x6000), nullptr,
                n.bounds.left, n.bounds.top + 24,
                n.bounds.right - n.bounds.left,
                n.bounds.bottom - n.bounds.top,
                SWP_NOZORDER);
        }
    }
    
    void OnRejected(const LiveNode& n) {
        char buf[256];
        sprintf(buf, "REJECTED: %s - hiding from IDE", n.label.c_str());
        OutputDebugStringA(buf);
        
        if (n.label.find("δ") != std::string::npos) {
            ShowWindow(GetDlgItem(ide_hwnd_, 0x6000), SW_HIDE);
        }
    }
    
    void OnMoved(const LiveNode& n, int x, int y) {
        // Live preview of movement
        if (n.state == ApprovalState::APPROVED) {
            OnApproved(n);
        }
    }
    
    bool IsCommitted() const { return committed_; }
    
    void Finalize() {
        schematic_.Commit();
        committed_ = true;
        
        auto approved = schematic_.GetApprovedNodes();
